import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';

const CompleteProfile = () => {
  const { user, login } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({
    phone: user?.phone || '',
    role: user?.role || 'student',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res = await api.put('/users/profile', form);
      // Update local user with new details
      const updatedUser = { ...user, phone: form.phone, role: form.role };
      login(localStorage.getItem('token'), updatedUser);
      navigate(form.role === 'admin' ? '/admin' : form.role === 'staff' ? '/staff' : '/student');
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to update profile');
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = {
    width: '100%', background: 'rgba(255,255,255,0.08)',
    border: '1px solid rgba(255,255,255,0.2)', borderRadius: 10,
    padding: '12px 16px', color: 'white', fontSize: 15, outline: 'none',
  };

  const labelStyle = {
    color: 'rgba(255,255,255,0.7)', fontSize: 13,
    fontWeight: 600, marginBottom: 6, display: 'block',
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0f0c29, #302b63, #24243e)',
      display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px',
    }}>
      <div style={{ width: '100%', maxWidth: 440 }}>

        <div className="text-center mb-4">
          <div style={{ fontSize: 56, marginBottom: 8 }}>👤</div>
          <h2 style={{ color: 'white', fontWeight: 800 }}>Complete Your Profile</h2>
          <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: 14 }}>
            Just a few more details to get you set up
          </p>
        </div>

        <div style={{
          background: 'rgba(255,255,255,0.05)', backdropFilter: 'blur(20px)',
          border: '1px solid rgba(255,255,255,0.1)', borderRadius: 20, padding: '36px 32px',
        }}>

          {/* Show Google account info */}
          <div style={{
            background: 'rgba(255,255,255,0.05)',
            border: '1px solid rgba(255,255,255,0.1)',
            borderRadius: 12, padding: '14px 16px', marginBottom: 24,
            display: 'flex', alignItems: 'center', gap: 12,
          }}>
            <div style={{
              width: 42, height: 42, borderRadius: '50%',
              background: 'linear-gradient(135deg, #e94560, #0f3460)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              color: 'white', fontWeight: 700, fontSize: 18, flexShrink: 0,
            }}>
              {user?.name?.charAt(0).toUpperCase()}
            </div>
            <div>
              <div style={{ color: 'white', fontWeight: 600, fontSize: 15 }}>{user?.name}</div>
              <div style={{ color: 'rgba(255,255,255,0.5)', fontSize: 13 }}>{user?.email}</div>
            </div>
            <div style={{ marginLeft: 'auto' }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
              </svg>
            </div>
          </div>

          {error && (
            <div className="alert alert-danger py-2 mb-3" style={{ borderRadius: 10, fontSize: 14 }}>
              ⚠️ {error}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label style={labelStyle}>
                📱 Phone Number
                <span style={{ color: 'rgba(255,255,255,0.3)', fontWeight: 400, marginLeft: 6 }}>
                  (for SMS alerts)
                </span>
              </label>
              <input type="tel" value={form.phone}
                onChange={e => setForm({ ...form, phone: e.target.value })}
                placeholder="+91 9876543210" style={inputStyle} />
            </div>

            <div className="mb-4">
              <label style={labelStyle}>🎓 Your Role</label>
              <select value={form.role}
                onChange={e => setForm({ ...form, role: e.target.value })}
                style={{ ...inputStyle, cursor: 'pointer' }}>
                <option value="student" style={{ background: '#1a1a2e' }}>👩‍🎓 Student</option>
                <option value="staff" style={{ background: '#1a1a2e' }}>👔 Staff</option>
              </select>
              <small style={{ color: 'rgba(255,255,255,0.3)', marginTop: 4, display: 'block' }}>
                Admin role must be assigned by an existing admin
              </small>
            </div>

            <button type="submit" disabled={loading} style={{
              width: '100%', background: 'linear-gradient(135deg, #e94560, #c0392b)',
              border: 'none', borderRadius: 10, padding: '14px',
              color: 'white', fontSize: 16, fontWeight: 700,
              cursor: loading ? 'not-allowed' : 'pointer', opacity: loading ? 0.7 : 1,
            }}>
              {loading ? '⌛ Saving...' : '✅ Complete Registration'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default CompleteProfile;
